#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
using namespace std;
typedef long long ll;ll n,R;int m,a[70],b[70];ll dp[70][2][2][2];
int main()
{
	ios::sync_with_stdio(false);cin.tie(0);cout.tie(0);
	int T;cin>>T; Begin:
	
	memset(a,0,sizeof(a));
	memset(b,0,sizeof(b));
	memset(dp,0,sizeof(dp));
	cin>>n>>R;--R;
	int A=0,B=0;while(n)a[++A]=n&1,n>>=1;
	while(R)b[++B]=R&1,R>>=1;m=max(A,B)+1;
//	rep(1,m,i)printf("%d",a[i]);puts("");
//	rep(1,m,i)printf("%d",b[i]);puts("");
	rep(0,1,t)
	{
		++dp[1][(a[1]+t)>>1][((a[1]+t)&1)!=t][0];
		if(t<=b[1])++dp[1][(a[1]+t)>>1][((a[1]+t)&1)!=t][1];
	}
//	printf("QAQ :: %lld\n",dp[1][0][1][1]);
	rep(1,m-1,d)
	{
		rep(0,1,i)//进位 
		{
			rep(0,1,j)//奇偶性 
			{
				ll *w=dp[d][i][j];
				rep(0,1,k)//枚举b填啥子
				{
					int ni=(i+a[d+1]+k)>>1,nj=j^(((i+a[d+1]+k)&1)!=k);
					dp[d+1][ni][nj][0]+=w[0];
					if(k<b[d+1])
					{
						dp[d+1][ni][nj][1]+=w[0];
					}
					else if(k==b[d+1])
					{
						dp[d+1][ni][nj][1]+=w[1];
					}
				}
			}
		}
	}
	
	printf("%lld\n",dp[m][0][1][1]);
	//why remote jude guale
	if(--T)goto Begin;return 0;
}
